keyframes_css:
@keyframes flicker {
  0%, 100% { transform: translateY(0) scaleY(1); opacity: 0.8; }
  25% { transform: translateY(-8px) scaleY(1.1); opacity: 0.9; }
  50% { transform: translateY(-4px) scaleY(0.95); opacity: 0.7; }
  75% { transform: translateY(-6px) scaleY(1.05); opacity: 0.85; }
}

@keyframes rise {
  0% { transform: translateY(0); opacity: 1; }
  100% { transform: translateY(-40px); opacity: 0; }
}

.demo-stage {
  background: #ffffff;
  display: flex;
  align-items: flex-end;
  justify-content: center;
  overflow: hidden;
}

.demo-stage .flame-core {
  width: 24px;
  height: 32px;
  background: linear-gradient(to top, #f5c9d4 0%, #f0e0c0 100%);
  border-radius: 50% 50% 40% 40%;
  animation: flicker 1.2s ease-in-out infinite;
  position: relative;
}

.demo-stage .flame-core::before {
  content: '';
  position: absolute;
  width: 16px;
  height: 24px;
  background: #f0e0c0;
  border-radius: 50% 50% 30% 30%;
  top: -8px;
  left: 4px;
  animation: flicker 1.4s ease-in-out infinite 0.1s;
}

.demo-stage .spark {
  position: absolute;
  width: 4px;
  height: 4px;
  background: #f5c9d4;
  border-radius: 50%;
  animation: rise 1.6s ease-out infinite;
}

.demo-stage .spark:nth-child(2) {
  left: 8px;
  animation-delay: 0.3s;
}

.demo-stage .spark:nth-child(3) {
  left: -8px;
  animation-delay: 0.6s;
}

@keyframes flicker {
  0% { transform: translateY(0) scaleY(0.8); opacity: 0.6; }
  50% { transform: translateY(-8px) scaleY(1.1); opacity: 0.9; }
  100% { transform: translateY(0) scaleY(0.8); opacity: 0.6; }
}

@keyframes sway {
  0%, 100% { transform: translateX(0); }
  50% { transform: translateX(3px); }
}

.demo-stage {
  background-color: #ffffff;
  width: 200px;
  height: 200px;
  display: flex;
  align-items: flex-end;
  justify-content: center;
  padding: 20px;
}

.demo-stage::before {
  content: '';
  width: 30px;
  height: 50px;
  background: linear-gradient(to top, #f5c9d4, #f0e0c0);
  border-radius: 50% 50% 40% 40%;
  animation: flicker 1.5s ease-in-out infinite, sway 2s ease-in-out infinite;
  filter: blur(2px);
}

.demo-stage::after {
  content: '';
  width: 20px;
  height: 35px;
  background: linear-gradient(to top, #f0e0c0, rgba(245, 201, 212, 0.3));
  border-radius: 50% 50% 30% 30%;
  position: absolute;
  animation: flicker 1.2s ease-in-out infinite 0.2s, sway 2.5s ease-in-out infinite 0.3s;
  filter: blur(3px);
  margin-left: 15px;
}

@keyframes wave {
  0% {
    transform: translateX(0) translateY(0);
  }
  25% {
    transform: translateX(20px) translateY(-12px);
  }
  50% {
    transform: translateX(40px) translateY(0);
  }
  75% {
    transform: translateX(20px) translateY(12px);
  }
  100% {
    transform: translateX(0) translateY(0);
  }
}

.demo-stage {
  background: #ffffff;
  width: 200px;
  height: 200px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.demo-stage .wave-line {
  width: 80px;
  height: 3px;
  background: #c9dff5;
  border-radius: 2px;
  animation: wave 1.6s ease-in-out infinite;
}

.demo-stage .wave-dot {
  width: 12px;
  height: 12px;
  background: #d4e8d0;
  border-radius: 50%;
  position: absolute;
  animation: wave 1.6s ease-in-out infinite;
  opacity: 0.7;
}

.demo-stage .wave-dot:nth-child(2) {
  animation-delay: 0.3s;
}

.demo-stage .wave-dot:nth-child(3) {
  animation-delay: 0.6s;
}

@keyframes breathe {
  0% {
    transform: scaleX(1);
    box-shadow: 0 0 20px rgba(100, 150, 255, 0.3);
  }
  50% {
    transform: scaleX(1.1);
    box-shadow: 0 0 40px rgba(100, 150, 255, 0.7);
  }
  100% {
    transform: scaleX(1);
    box-shadow: 0 0 20px rgba(100, 150, 255, 0.3);
  }
}

.demo-stage {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 200px;
  height: 200px;
  background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
}

.demo-stage .wall {
  width: 80px;
  height: 120px;
  background: linear-gradient(90deg, #4a6fa5 0%, #2d5a8c 50%, #4a6fa5 100%);
  border-radius: 10px;
  animation: breathe 3s ease-in-out infinite;
  transform-origin: center;
}

@keyframes sand-flow {
  0% {
    height: 80px;
    opacity: 1;
  }
  50% {
    height: 10px;
    opacity: 1;
  }
  100% {
    height: 80px;
    opacity: 1;
  }
}

@keyframes sand-fall {
  0% {
    transform: translateY(0);
    opacity: 0;
  }
  10% {
    opacity: 1;
  }
  90% {
    opacity: 1;
  }
  100% {
    transform: translateY(60px);
    opacity: 0;
  }
}

@keyframes rotate-glass {
  0%, 49% {
    transform: rotateZ(0deg);
  }
  50%, 100% {
    transform: rotateZ(180deg);
  }
}

.demo-stage {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 200px;
  height: 200px;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
}

.demo-stage .hourglass {
  position: relative;
  width: 60px;
  height: 120px;
  animation: rotate-glass 4s ease-in-out infinite;
}

.demo-stage .glass-top {
  position: absolute;
  top: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 50px;
  height: 50px;
  border: 3px solid #fff;
  border-bottom: none;
  border-radius: 8px 8px 0 0;
  box-sizing: border-box;
}

.demo-stage .glass-middle {
  position: absolute;
  top: 48px;
  left: 50%;
  transform: translateX(-50%);
  width: 8px;
  height: 24px;
  background: #fff;
  border-radius: 2px;
}

.demo-stage .glass-bottom {
  position: absolute;
  bottom: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 50px;
  height: 50px;
  border: 3px solid #fff;
  border-top: none;
  border-radius: 0 0 8px 8px;
  box-sizing: border-box;
}

.demo-stage .sand-top {
  position: absolute;
  top: 6px;
  left: 50%;
  transform: translateX(-50%);
  width: 30px;
  height: 80px;
  background: linear-gradient(to bottom, #ffd700, #ffed4e);
  border-radius: 50%;
  animation: sand-flow 4s ease-in-out infinite;
}

.demo-stage .sand-falling {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translateX(-50%);
  width: 3px;
  height: 3px;
  background: #ffd700;
  border-radius: 50%;
  animation: sand-fall 0.8s ease-in infinite;
}

.demo-stage .sand-falling:nth-child(4) {
  animation-delay: 0s;
}

.demo-stage .sand-falling:nth-child(5) {
  animation-delay: 0.2s;
}

.demo-stage .sand-falling:nth-child(6) {
  animation-delay: 0.4s;
}

.demo-stage .sand-falling:nth-child(7) {
  animation-delay: 0.6s;
}

.demo-stage .sand-bottom {
  position: absolute;
  bottom: 6px;
  left: 50%;
  transform: translateX(-50%);
  width: 30px;
  height: 10px;
  background: linear-gradient(to bottom, #ffed4e, #ffd700);
  border-radius: 50%;
  animation: sand-flow 4s ease-in-out infinite;
  animation-direction: reverse;
}

@keyframes float-up {
  0% {
    transform: translateY(0) rotateZ(0deg);
    opacity: 1;
  }
  100% {
    transform: translateY(-120px) rotateZ(360deg);
    opacity: 0;
  }
}

@keyframes sway {
  0%, 100% {
    transform: translateX(0);
  }
  50% {
    transform: translateX(15px);
  }
}

.demo-stage {
  width: 200px;
  height: 200px;
  background: linear-gradient(180deg, #87ceeb 0%, #e0f6ff 100%);
  position: relative;
  overflow: hidden;
  border-radius: 8px;
}

.demo-stage .floating-object {
  position: absolute;
  width: 30px;
  height: 30px;
  background: radial-gradient(circle at 30% 30%, #ffd700, #ffed4e);
  border-radius: 50%;
  bottom: 0;
  left: 50%;
  margin-left: -15px;
  animation: float-up 3s ease-in infinite, sway 2s ease-in-out infinite;
  box-shadow: 0 0 15px rgba(255, 215, 0, 0.6);
}

.demo-stage .floating-object:nth-child(2) {
  width: 20px;
  height: 20px;
  left: 30%;
  margin-left: -10px;
  animation-delay: 0.5s;
  background: radial-gradient(circle at 30% 30%, #ff6b9d, #ffa5c9);
  box-shadow: 0 0 12px rgba(255, 107, 157, 0.5);
}

.demo-stage .floating-object:nth-child(3) {
  width: 25px;
  height: 25px;
  left: 70%;
  margin-left: -12.5px;
  animation-delay: 1s;
  background: radial-gradient(circle at 30% 30%, #87ceeb, #b0e0e6);
  box-shadow: 0 0 12px rgba(135, 206, 235, 0.5);
}

@keyframes rise {
  0% {
    transform: translateY(80px);
    opacity: 0.3;
  }
  50% {
    opacity: 1;
  }
  100% {
    transform: translateY(-80px);
    opacity: 0.3;
  }
}

@keyframes float {
  0%, 100% {
    transform: translateX(0px) scale(1);
  }
  50% {
    transform: translateX(20px) scale(0.8);
  }
}

.demo-stage {
  width: 200px;
  height: 200px;
  background: linear-gradient(to bottom, #1a1a2e, #0f3460);
  border-radius: 10px;
  overflow: hidden;
  position: relative;
}

.demo-stage::before {
  content: '';
  position: absolute;
  bottom: 20px;
  left: 50%;
  transform: translateX(-50%);
  width: 80px;
  height: 60px;
  background: radial-gradient(ellipse at 30% 30%, #00ff88, #00cc66);
  border-radius: 50%;
  box-shadow: 0 0 20px rgba(0, 255, 136, 0.6), inset -2px -2px 10px rgba(0, 0, 0, 0.3);
  animation: rise 3s ease-in-out infinite;
}

.demo-stage::after {
  content: '';
  position: absolute;
  top: 30px;
  left: 50%;
  transform: translateX(-50%);
  width: 60px;
  height: 40px;
  background: radial-gradient(ellipse at 40% 40%, #00ffaa, #00dd77);
  border-radius: 50%;
  box-shadow: 0 0 15px rgba(0, 255, 170, 0.5), inset -1px -1px 8px rgba(0, 0, 0, 0.2);
  animation: rise 3.5s ease-in-out infinite 0.5s;
  opacity: 0.7;
}

.liquid-drop {
  position: absolute;
  width: 20px;
  height: 20px;
  background: radial-gradient(circle at 30% 30%, #00ffcc, #00aa88);
  border-radius: 50%;
  box-shadow: 0 0 10px rgba(0, 255, 204, 0.7);
  animation: rise 2.8s ease-in-out infinite;
}

.liquid-drop:nth-child(1) {
  left: 40px;
  animation-delay: 0.2s;
}

.liquid-drop:nth-child(2) {
  left: 90px;
  animation-delay: 0.8s;
}

.liquid-drop:nth-child(3) {
  left: 140px;
  animation-delay: 1.4s;
}

@keyframes fall {
  0% {
    transform: translateY(-20px);
    opacity: 1;
  }
  100% {
    transform: translateY(180px);
    opacity: 0;
  }
}

.demo-stage {
  width: 200px;
  height: 200px;
  background: linear-gradient(180deg, #1a1a2e 0%, #16213e 100%);
  border-radius: 8px;
  overflow: hidden;
  position: relative;
}

.demo-stage::before,
.demo-stage::after {
  content: '';
  position: absolute;
  width: 3px;
  height: 3px;
  background: #64b5f6;
  border-radius: 50%;
  animation: fall 1.5s infinite ease-in;
}

.demo-stage::before {
  left: 30%;
  animation-delay: 0s;
}

.demo-stage::after {
  left: 60%;
  animation-delay: 0.5s;
}

.demo-stage .drop1 {
  position: absolute;
  width: 3px;
  height: 3px;
  background: #64b5f6;
  border-radius: 50%;
  left: 45%;
  animation: fall 1.5s infinite ease-in;
  animation-delay: 1s;
}

.demo-stage .drop2 {
  position: absolute;
  width: 3px;
  height: 3px;
  background: #64b5f6;
  border-radius: 50%;
  left: 75%;
  animation: fall 1.5s infinite ease-in;
  animation-delay: 0.25s;
}

.demo-stage .drop3 {
  position: absolute;
  width: 3px;
  height: 3px;
  background: #64b5f6;
  border-radius: 50%;
  left: 15%;
  animation: fall 1.5s infinite ease-in;
  animation-delay: 0.75s;
}
